import sys
from collections import deque
from typing import List

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def leftView(self, root: TreeNode) -> List[int]:
        if not root:
            return []
        result = []
        queue = deque([root])
        while queue:
            level_size = len(queue)
            result.append(queue[0].val)
            for _ in range(level_size):
                node = queue.popleft()
                if node.left:
                    queue.append(node.left)
                if node.right:
                    queue.append(node.right)
        return result

    def rightView(self, root: TreeNode) -> List[int]:
        if not root:
            return []
        result = []
        queue = deque([root])
        while queue:
            level_size = len(queue)
            result.append(queue[-1].val)
            for _ in range(level_size):
                node = queue.popleft()
                if node.left:
                    queue.append(node.left)
                if node.right:
                    queue.append(node.right)
        return result

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        nodes = []
        for _ in range(n):
            val = next(it)
            if val == 'X':
                nodes.append(None)
            else:
                nodes.append(int(val))
        root = TreeNode(nodes[0])
        queue = deque([root])
        i = 1
        while queue and i < n:
            node = queue.popleft()
            if nodes[i] is not None:
                node.left = TreeNode(nodes[i])
                queue.append(node.left)
            i += 1
            if i < n and nodes[i] is not None:
                node.right = TreeNode(nodes[i])
                queue.append(node.right)
            i += 1
        sol = Solution()
        left_view = sol.leftView(root)
        right_view = sol.rightView(root)
        print(' '.join(map(str, left_view)))
        print(' '.join(map(str, right_view)))
    except StopIteration:
        sys.exit(0)

