#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<int> leftView(TreeNode* root) {
        if (!root) return {};
        vector<int> result;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            int level_size = q.size();
            result.push_back(q.front()->val);
            for (int i = 0; i < level_size; i++) {
                TreeNode* node = q.front();
                q.pop();
                if (node->left) q.push(node->left);
                if (node->right) q.push(node->right);
            }
        }
        return result;
    }

    vector<int> rightView(TreeNode* root) {
        if (!root) return {};
        vector<int> result;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            int level_size = q.size();
            result.push_back(q.back()->val);
            for (int i = 0; i < level_size; i++) {
                TreeNode* node = q.front();
                q.pop();
                if (node->left) q.push(node->left);
                if (node->right) q.push(node->right);
            }
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> nodes(n);
    for (int i = 0; i < n; i++) {
        string val;
        cin >> val;
        if (val == "X") {
            nodes[i] = -1;
        } else {
            nodes[i] = stoi(val);
        }
    }
    TreeNode* root = new TreeNode(nodes[0]);
    queue<TreeNode*> q;
    q.push(root);
    int i = 1;
    while (!q.empty() && i < n) {
        TreeNode* node = q.front();
        q.pop();
        if (nodes[i] != -1) {
            node->left = new TreeNode(nodes[i]);
            q.push(node->left);
        }
        i++;
        if (i < n && nodes[i] != -1) {
            node->right = new TreeNode(nodes[i]);
            q.push(node->right);
        }
        i++;
    }
    Solution sol;
    vector<int> left_view = sol.leftView(root);
    vector<int> right_view = sol.rightView(root);
    for (int val : left_view) {
        cout << val << " ";
    }
    cout << endl;
    for (int val : right_view) {
        cout << val << " ";
    }
    cout << endl;
    return 0;
}
